import { Box, List, ListItemButton, ListItemText } from "@mui/material";
import { useNavigate, useLocation } from "react-router-dom";
import { useEffect, useState } from "react";

export default function Sidebar() {
  const navigate = useNavigate();
  const location = useLocation();

  const [role, setRole] = useState("");

  useEffect(() => {
    const storedRole = localStorage.getItem("role");
    console.log("SIDEBAR ROLE:", storedRole);
    setRole(storedRole);
  }, []);

  return (
    <Box
      sx={{
        width: 220,
        height: "100vh",
        background: "#1e293b",
        color: "#fff",
        p: 2,
      }}
    >
      <List>
        {/* 👑 SUPERADMIN */}
        {role === "superadmin" && (
          <>
            <ListItemButton onClick={() => navigate("/superadmin")}>
              <ListItemText primary="Create Organization" />
            </ListItemButton>

            <ListItemButton onClick={() => navigate("/organizations")}>
              <ListItemText primary="Organization Management" />
            </ListItemButton>
          </>
        )}

        {/* 🧑‍💼 ADMIN */}
        {role === "admin" && (
          <>
            <ListItemButton onClick={() => navigate("/admin/project-setup")}>
              <ListItemText primary="Project Setup" />
            </ListItemButton>

            <ListItemButton
              onClick={() => navigate("/admin/project-management")}
            >
              <ListItemText primary="Project Management" />
            </ListItemButton>
          </>
        )}
      </List>
    </Box>
  );
}
